class Solution {
public:
    int brokenCalc(int startValue, int target) {
        int operations = 0;
        while (startValue != target) {
            if (startValue < target) {
                startValue *= 2;
            } else {
                startValue--;
            }
            operations++;
        }
        return operations;
    }
};
```
